{"code": "import json
import os

# Find and load articles data
articles = []

# Check all local variables for the articles data
for key, value in locals().items():
    if isinstance(value, list) and len(value) > 0:
        if isinstance(value[0], dict) and 'description' in value[0]:
            articles = value
            break

# If not found in variables, try to load from file
if not articles:
    # Try to find the file path variable
    for key, value in locals().items():
        if isinstance(value, str) and '/tmp/' in value:
            file_path = value
            if os.path.exists(file_path):
                with open(file_path, 'r') as f:
                    articles = json.load(f)
                    break

# Define sports keywords
sports_keywords = [
    'football', 'soccer', 'basketball', 'baseball', 'tennis', 'golf', 
    'cricket', 'hockey', 'rugby', 'athlete', 'olympic',
    'nba', 'nfl', 'mlb', 'nhl', 'premier league', 'world cup',
    'stadium', 'arena', 'championship', 'tournament', 'match',
    'victory', 'medal', 'gold medal', 'coach', 'player', 'team', 'game'
]

def is_sports_article(article):
    title_desc = (article.get('title', '') + ' ' + article.get('description', '')).lower()
    return any(keyword in title_desc for keyword in sports_keywords)

sports_articles = [a for a in articles if is_sports_article(a)]

longest_article = None
max_len = 0
for article in sports_articles:
    desc_len = len(article.get('description', ''))
    if desc_len > max_len:
        max_len = desc_len
        longest_article = article

result = {
    'sports_count': len(sports_articles),
    'found_longest': longest_article is not None,
    'title': longest_article.get('title') if longest_article else None,
    'length': max_len
}

print('__RESULT__:')
print(json.dumps(result))"}

