{"code": "import json
import os

# Let's try to find the articles data systematically
articles_vars = {}

# Check all variables first
globals_dict = globals().copy()
locals_dict = locals().copy()

for name, value in locals_dict.items():
    if isinstance(value, list) and len(value) > 0 and isinstance(value[0], dict):
        if 'title' in value[0] or 'description' in value[0]:
            articles_vars[name] = len(value)

print('Found potential articles variables:', articles_vars)

# Get the actual articles data
articles = []
if articles_vars:
    var_name = max(articles_vars.items(), key=lambda x: x[1])[0]
    articles = locals()[var_name]
    print(f'Using variable: {var_name} with {len(articles)} articles')
else:
    # Look for file paths
    file_vars = {}
    for name, value in locals_dict.items():
        if isinstance(value, str) and ('output' in value or '/tmp/' in value):
            file_vars[name] = value

    print('Found potential file paths:', file_vars)

    # Try to load from the most likely file path
    for name, path in file_vars.items():
        if os.path.exists(path):
            with open(path, 'r') as f:
                articles = json.load(f)
            print(f'Loaded {len(articles)} articles from {path}')
            break

# Show some sample articles
if articles:
    print(f'Processing {len(articles)} articles...')
    for i, article in enumerate(articles[:10]):
        title = article.get('title', '')
        desc = article.get('description', '')
        print(f'{i}: {title[:50]} | {desc[:60]}...')

result = {'status': 'loaded' if articles else 'failed', 'count': len(articles)}
print('__RESULT__:')
print(json.dumps(result))"}

